# -*- coding: utf-8 -*-

"""Vercel Python function: /api/sales_dashboard

Sales Dashboard (production)

Requested layout:
- Total Sales (KPI)
- Sales by Pipeline
- Owner table with columns:
  - Owner
  - Opps Ran
  - Sales
  - Opp2Prelim% (Sales / Opps Ran)

Data sources:
- /api/metrics/sales?format=json&year=YYYY&month=M
- /api/metrics/opportunities_ran?format=json&year=YYYY&month=M

Style:
- PatientPop green/blue (primary green #00C853, accent blue #2196F3)
"""

from __future__ import annotations

from datetime import datetime
from http.server import BaseHTTPRequestHandler
from urllib.parse import parse_qs, urlparse


def render_html(year: int, month: int) -> str:
    html = r"""<!doctype html>
<html>
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Happy Solar — Sales Dashboard</title>
  <link rel="icon" type="image/png" href="data:image/png;base64," />
  <style>
    :root {
      --bg: #f5f7fa;
      --card: #ffffff;
      --border: #e8ecf0;
      --text: #111827;
      --muted: #6b7280;
      --muted2: #9ca3af;

      /* PatientPop */
      --green: #00C853;
      --green2: #2EE07A;
      --blue: #2196F3;
      --blue2: #64B5F6;

      --purple: #8b5cf6;
      --cyan: #06b6d4;
      --amber: #f59e0b;
    }

    body {
      font-family: -apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;
      margin:0;
      background: var(--bg);
      color: var(--text);
    }

    .wrap { padding: 22px; max-width: 1180px; margin: 0 auto; }

    .topbar {
      position: relative;
      display:flex;
      align-items:flex-start;
      justify-content: space-between;
      gap: 18px;
      flex-wrap: wrap;
      padding: 18px 20px;
      border-radius: 14px;
      background: var(--card);
      border: 2px solid var(--border);
      box-shadow: 0 2px 6px rgba(17,24,39,0.06);
    }

    .title {
      font-size: 22px;
      font-weight: 900;
      color: #1a2b4a;
      letter-spacing: -0.02em;
    }

    .subtitle { margin-top: 4px; color: var(--muted); font-size: 13px; }

    .accentline {
      height: 3px;
      width: 180px;
      border-radius: 999px;
      background: linear-gradient(90deg, var(--green) 0%, var(--blue) 55%, rgba(100,181,246,0) 100%);
      margin-top: 10px;
    }

    .brandCenter {
      position: absolute;
      left: 50%;
      top: 12px;
      transform: translateX(-50%);
      display:flex;
      align-items:center;
      justify-content:center;
      pointer-events:none;
    }
    .brandCenter img { height: 56px; width: auto; display:block; }

    .nav {
      margin-top: 12px;
      display:flex;
      gap: 10px;
      flex-wrap: wrap;
      justify-content: center;
      width: 100%;
    }

    .navbtn {
      display:inline-flex;
      align-items:center;
      padding: 9px 12px;
      border-radius: 12px;
      border: 1px solid var(--border);
      background: #fff;
      color: #1f2937;
      font-size: 13px;
      font-weight: 800;
      text-decoration:none;
    }

    .navbtn:hover {
      border-color: rgba(0,200,83,0.45);
      box-shadow: 0 1px 2px rgba(17,24,39,0.06);
    }

    .navbtn.active {
      background: rgba(0,200,83,0.10);
      border-color: rgba(0,200,83,0.45);
      color: #0a7a34;
    }

    .adminSettings {
      position: absolute;
      top: 16px;
      right: 18px;
    }

    .missingDisposTop {
      position: absolute;
      top: 16px;
      right: 158px;
    }

    .filters { display:flex; align-items:center; gap: 10px; flex-wrap: wrap; }
    .filter { display:flex; align-items:center; gap: 8px; }

    /* Period pills (shared dashboard behavior) */
    .pillbar { margin-top: 12px; display:flex; gap: 10px; flex-wrap: wrap; }
    .pill {
      display:inline-flex;
      align-items:center;
      padding: 8px 12px;
      border-radius: 999px;
      border: 1px solid var(--border);
      background: #fff;
      color: #334155;
      font-size: 12px;
      font-weight: 950;
      cursor: pointer;
      user-select: none;
    }
    .pill:hover { border-color: rgba(0,200,83,0.45); box-shadow: 0 1px 2px rgba(17,24,39,0.06); }
    .pill.active { background: rgba(0,200,83,0.10); border-color: rgba(0,200,83,0.45); color: #0a7a34; }
    .filter-label {
      font-size: 12px;
      color: var(--muted);
      background:#f0f2f5;
      padding: 9px 10px;
      border-radius: 10px;
      border: 1px solid var(--border);
    }

    select, button, input[type=date] {
      background: var(--card);
      color: var(--text);
      border: 1px solid var(--border);
      border-radius: 10px;
      padding: 9px 12px;
      font-size: 13px;
    }

    button {
      background: var(--green);
      border-color: var(--green);
      color: #fff;
      font-weight: 900;
      cursor:pointer;
    }

    .grid {
      display:grid;
      grid-template-columns: repeat(12, 1fr);
      gap: 14px;
      margin-top: 14px;
      align-content: start;
    }

    .card {
      background: var(--card);
      border: 1px solid var(--border);
      border-radius: 14px;
      padding: 16px 18px;
      box-shadow: 0 1px 3px rgba(17,24,39,0.06);
      min-height: 120px;
    }

    .card-header { display:flex; align-items:flex-start; justify-content: space-between; gap: 10px; }
    .card-title { font-size: 13px; font-weight: 800; color: var(--muted); }

    .kpi { font-size: 46px; font-weight: 950; margin-top: 8px; letter-spacing: -0.02em; }
    .meta { margin-top: 6px; color: var(--muted2); font-size: 12px; }

    .span-4 { grid-column: span 4; }
    .span-8 { grid-column: span 8; }
    .span-12 { grid-column: span 12; }

    @media (max-width: 980px) {
      .span-4, .span-8, .span-12 { grid-column: span 12; }
    }

    .skeleton { color: var(--muted2); font-size: 13px; }

    /* Vertical bars (same pattern as company overview) */
    .vchart { margin-top: 10px; }
    .vwrap {
      display:flex;
      align-items:stretch;
      justify-content:center;
      gap: 10px;
      height: 260px;
      padding: 12px 12px;
      background:#fafbfc;
      border:1px solid var(--border);
      border-radius:12px;
      overflow-x:auto;
    }
    .vcol {
      width: 86px;
      flex: 0 0 86px;
      height: 100%;
      display:flex;
      flex-direction:column;
      align-items:center;
      gap: 8px;
    }
    .vbarArea {
      width: 100%;
      flex: 1;
      display:flex;
      align-items:stretch;
      justify-content:center;
    }
    .vbarStack {
      width: 100%;
      height: 100%;
      display:flex;
      flex-direction:column;
      justify-content:flex-end;
      align-items:stretch;
      gap: 6px;
    }
    .vval {
      font-size: 12px;
      color: var(--muted);
      font-variant-numeric: tabular-nums;
      text-align:center;
      width:100%;
    }
    .vbar {
      width: 100%;
      border-radius: 14px 14px 6px 6px;
    }
    .vlabel {
      font-size: 11px;
      color: var(--muted);
      text-align:center;
      width: 100%;
      overflow:hidden;
      text-overflow:ellipsis;
      white-space:nowrap;
    }

    /* Owner table */
    .tablewrap {
      margin-top: 10px;
      overflow:auto;
      border: 1px solid var(--border);
      border-radius: 12px;
      background: #fafbfc;
    }
    table { width:100%; border-collapse: collapse; min-width: 760px; }
    th, td { padding: 10px 12px; font-size: 13px; border-bottom: 1px solid var(--border); text-align:left; }
    th { font-size: 12px; color: var(--muted); font-weight: 900; background: #f3f5f7; position: sticky; top: 0; }
    td.num { text-align:right; font-variant-numeric: tabular-nums; }
    tr.total td { font-weight: 900; background: #ffffff; }

    a { color: var(--green); text-decoration: none; }
    a:hover { text-decoration: underline; }
  

    /* Mobile optimizations */
    @media (max-width: 820px) {
      .wrap { padding: 14px; }
      .topbar { padding: 14px 14px; }
      .title { font-size: 18px; }
      .navbtn { padding: 8px 10px; font-size: 12px; }
      .filters { gap: 8px; }
      .filter-label { font-size: 11px; }
      .kpi { font-size: 38px; }
      .card { padding: 14px 14px; }
      table { display: block; overflow-x: auto; white-space: nowrap; }
    }

    @media (max-width: 820px) {
      .grid { grid-template-columns: repeat(2, 1fr); }
      .card { min-height: 100px; }
      .kpi { font-size: 34px; }
      .span-12 { grid-column: span 2; }
    }

    @media (max-width: 520px) {
      .grid { grid-template-columns: 1fr; }
      .span-3, .span-4, .span-6, .span-8, .span-9, .span-12 { grid-column: span 12; }
      .adminSettings { top: 12px; right: 12px; }
      .missingDisposTop { top: 12px; right: 134px; }
      .brandCenter { display:none; }
    }
</style>
</head>
<body>
  <div class="wrap">
    <div class="topbar">
      <div>
        <div class="title">Sales Dashboard</div>
        <div class="subtitle">Happy Solar — sales + owner performance</div>
        <div class="accentline"></div>
        <div class="nav">
          <a class="navbtn" href="/api/company_overview">Company overview</a>
          <a class="navbtn active" href="/api/sales_dashboard">Sales dashboard</a>
          <a class="navbtn" href="/api/fma_dashboard">FMA Dashboard</a>
          <a class="navbtn" href="/api/virtual_team_dashboard">Virtual Team</a>
        </div>
      </div>


      <div class="brandCenter">
        <img alt="Happy Solar" src="data:image/png;base64," />
      </div>
      <div class="filters">
        <a class="navbtn missingDisposTop" href="/api/missing_dispos">Missing Dispos</a>
        <a class="navbtn adminSettings" href="/api/settings">Admin Settings</a>
        <div class="filter">
          <div class="filter-label">Year</div>
          <select id="year"></select>
        </div>
        <div class="filter">
          <div class="filter-label">Month</div>
          <select id="month"></select>
        </div>
        <button id="apply">Apply</button>
        <div class="filter">
          <div class="filter-label">Start</div>
          <input id="startDate" type="date" />
        </div>
        <div class="filter">
          <div class="filter-label">End</div>
          <input id="endDate" type="date" />
        </div>
        <button id="clearRange" style="background:#fff;color:#1f2937;border-color:var(--border);font-weight:900">Clear</button>
        
      </div>

      <div class="pillbar" id="periodTabs">
        <div class="pill" data-period="thismo">This Month</div>
        <div class="pill" data-period="lastmo">Last Month</div>
        <div class="pill" data-period="thiswk">This Week</div>
        <div class="pill" data-period="yesterday">Yesterday</div>
        <div class="pill" data-period="2w">Last 2 Weeks</div>
        <div class="pill" data-period="custom">Custom</div>
      </div>
    </div>

    <div class="grid">
      <div class="card span-12">
        <div class="card-header" style="display:grid; grid-template-columns:1fr auto 1fr; align-items:start; margin-bottom:4px;">
          <div style="justify-self:start;">
            <div class="card-title">Sales by Pipeline</div>
            <div class="meta">Vertical bars</div>
          </div>
          <div style="text-align:center; line-height:1; justify-self:center;">
            <div class="meta" style="margin-top:0; font-size:12px; font-weight:900; letter-spacing:.04em;">TOTAL SALES</div>
            <div id="totalSales" style="font-size:44px; font-weight:950; line-height:1; letter-spacing:-.02em;">—</div>
            <div class="meta" id="salesMeta" style="margin-top:2px"></div>
          </div>
          <div></div>
        </div>
        <div class="vchart" id="salesByPipelineV"><div class="skeleton">Loading…</div></div>
      </div>

      <div class="card span-12">
        <div class="card-header">
          <div>
            <div class="card-title">Owner Performance</div>
            <div class="meta">Opp2Prelim = Sales / Opps Ran (Opps Ran uses appointmentOccurredAt month window)</div>
          </div>
          <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
            <div class="meta" style="margin-top:0">Lead Gen Source</div>
            <select id="ownerLeadSource" style="border:1px solid var(--border); border-radius:10px; padding:8px 10px; font-size:13px; font-weight:900;">
              <option value="">All</option>
              <option value="Doors">Doors</option>
              <option value="Phones">Phones</option>
              <option value="3PL">3PL</option>
              <option value="Self Gen">Self Gen</option>
              <option value="none">none</option>
            </select>
          </div>
        </div>
        <div class="tablewrap">
          <table>
            <thead>
              <tr>
                <th>Owner</th>
                <th style="text-align:right">Opps Ran</th>
                <th style="text-align:right">Sales</th>
                <th style="text-align:right">Opp2Prelim%</th>
              </tr>
            </thead>
            <tbody id="ownerRows">
              <tr><td colspan="4" class="skeleton">Loading…</td></tr>
            </tbody>
          </table>
        </div>
      </div>

      <div class="card span-12">
        <div class="card-header">
          <div class="card-title">Self Gen Opps</div>
          <div class="meta">By Setter Last Name</div>
        </div>
        <div class="tablewrap">
          <table>
            <thead>
              <tr>
                <th>Setter Last Name</th>
                <th style="text-align:right">Opps Created</th>
                <th style="text-align:right">Opps Ran</th>
                <th style="text-align:right">Demo %</th>
              </tr>
            </thead>
            <tbody id="selfGenRows">
              <tr><td colspan="4" class="skeleton">Loading…</td></tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  </div>

<script>
  const defaultYear = __YEAR__;
  const defaultMonth = __MONTH__;

  const palette = [
    'var(--green)',
    'var(--blue)',
    'var(--purple)',
    'var(--cyan)',
    'var(--amber)'
  ];

  function setOptions(sel, options, value) {
    sel.innerHTML = '';
    for (const opt of options) {
      const o = document.createElement('option');
      o.value = String(opt.value);
      o.textContent = opt.label;
      if (String(opt.value) === String(value)) o.selected = true;
      sel.appendChild(o);
    }
  }

  function renderVertical(container, data) {
    const entries = Object.entries(data || {}).sort((a,b)=>b[1]-a[1]);
    if (!entries.length) {
      container.innerHTML = '<div class="skeleton">No data</div>';
      return;
    }
    const maxV = Math.max(...entries.map(([,v])=>Number(v)||0), 1);
    let html = '<div class="vwrap">';
    let i = 0;
    for (const [n, val] of entries) {
      const v = Number(val) || 0;
      const scale = maxV > 0 ? (v / maxV) : 0;
      const color = palette[i % palette.length];
      i++;
      html += `
        <div class="vcol" title="${n}">
          <div class="vbarArea">
            <div class="vbarStack">
              <div class="vval">${v}</div>
              <div class="vbar" style="background:${color}; height:${(scale*100).toFixed(2)}%"></div>
            </div>
          </div>
          <div class="vlabel">${n}</div>
        </div>`;
    }
    html += '</div>';
    container.innerHTML = html;
  }

  function pct(sales, ran) {
    const s = Number(sales||0);
    const r = Number(ran||0);
    if (r <= 0) return null;
    return (s / r) * 100;
  }

  function canonicalOwner(name) {
    const raw0 = (name || '').toString().trim();
    if (!raw0) return '—';

    // normalize internal whitespace (handles double spaces, etc.)
    const raw = raw0.replace(/\s+/g, ' ').trim();
    const low = raw.toLowerCase();

    // Combine owners for dashboard reporting
    if (low === 'jeff salas' || low === 'ollie calabrese') return 'Ollie Calabrese / Jeff Salas';

    return raw;
  }

  function rangeParams() {
    const s = (document.getElementById('startDate').value || '').trim();
    const e = (document.getElementById('endDate').value || '').trim();
    if (s && e) return `&start=${encodeURIComponent(s)}&end=${encodeURIComponent(e)}`;
    return '';
  }

  // selectors (must exist before we read yearSel/monthSel)
  const yearSel = document.getElementById('year');
  const monthSel = document.getElementById('month');

  // Persist range in URL so the UI always reflects the active range
  const pageUrl = new URL(window.location.href);
  const urlStart = pageUrl.searchParams.get('start') || '';
  const urlEnd = pageUrl.searchParams.get('end') || '';

  const rangeMetaEl = document.getElementById('rangeMeta');

  function daysInMonth(y, m) {
    return new Date(Number(y), Number(m), 0).getDate();
  }

  function setActive(period) {
    document.querySelectorAll('#periodTabs .pill').forEach(x => x.classList.toggle('active', x.dataset.period === period));
  }

  function setUrlRange(s, e) {
    const u = new URL(window.location.href);
    if (s && e) {
      u.searchParams.set('start', s);
      u.searchParams.set('end', e);
    } else {
      u.searchParams.delete('start');
      u.searchParams.delete('end');
    }
    window.location.href = u.toString();
  }

  function ymd(d) {
    const yyyy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2,'0');
    const dd = String(d.getDate()).padStart(2,'0');
    return `${yyyy}-${mm}-${dd}`;
  }

  if (urlStart && urlEnd) {
    document.getElementById('startDate').value = urlStart;
    document.getElementById('endDate').value = urlEnd;
    if (rangeMetaEl) rangeMetaEl.textContent = `${urlStart} → ${urlEnd}`;
    setActive('custom');
  } else {
    // Default to month window shown by the Year/Month selectors
    const y0 = yearSel.value;
    const m0 = monthSel.value;
    const s0 = `${y0}-${String(m0).padStart(2,'0')}-01`;
    const e0 = `${y0}-${String(m0).padStart(2,'0')}-${String(daysInMonth(y0, m0)).padStart(2,'0')}`;
    document.getElementById('startDate').value = s0;
    document.getElementById('endDate').value = e0;
    if (rangeMetaEl) rangeMetaEl.textContent = `Month: ${s0} → ${e0}`;
    setActive('thismo');
  }

  // Period tab click behavior (sets URL start/end)
  document.querySelectorAll('#periodTabs .pill').forEach(p => {
    p.addEventListener('click', () => {
      const per = p.dataset.period;
      const y = Number(yearSel.value);
      const m = Number(monthSel.value);
      const today = new Date();

      if (per === 'custom') {
        setActive('custom');
        return;
      }

      if (per === 'thismo') {
        const s = `${y}-${String(m).padStart(2,'0')}-01`;
        const e = `${y}-${String(m).padStart(2,'0')}-${String(daysInMonth(y,m)).padStart(2,'0')}`;
        setUrlRange(s, e);
      }

      if (per === 'lastmo') {
        const dt = new Date(y, m-2, 1);
        const y2 = dt.getFullYear();
        const m2 = dt.getMonth()+1;
        const s = `${y2}-${String(m2).padStart(2,'0')}-01`;
        const e = `${y2}-${String(m2).padStart(2,'0')}-${String(daysInMonth(y2,m2)).padStart(2,'0')}`;
        setUrlRange(s, e);
      }

      if (per === 'yesterday') {
        const d = new Date(today.getFullYear(), today.getMonth(), today.getDate()-1);
        const s = ymd(d);
        setUrlRange(s, s);
      }

      if (per === '2w') {
        const d0 = new Date(today.getFullYear(), today.getMonth(), today.getDate()-13);
        setUrlRange(ymd(d0), ymd(today));
      }

      if (per === 'thiswk') {
        // Monday-start
        const dow = (today.getDay() + 6) % 7; // Mon=0
        const mon = new Date(today.getFullYear(), today.getMonth(), today.getDate()-dow);
        setUrlRange(ymd(mon), ymd(today));
      }
    });
  });

  async function load() {
    const y = yearSel.value;
    const m = monthSel.value;

    const rp = rangeParams();
    const salesUrl = `/api/metrics/sales?format=json&year=${encodeURIComponent(y)}&month=${encodeURIComponent(m)}${rp}`;
    const ranUrl = `/api/metrics/opportunities_ran?format=json&year=${encodeURIComponent(y)}&month=${encodeURIComponent(m)}${rp}`; // now filtered by appointmentOccurredAt

    const ownerLeadSel = document.getElementById('ownerLeadSource');
    const ownerLead = ownerLeadSel ? String(ownerLeadSel.value || '') : '';
    const ownerLeadParam = ownerLead ? `&lead_source=${encodeURIComponent(ownerLead)}` : '';

    document.getElementById('totalSales').textContent = '…';
    document.getElementById('salesByPipelineV').innerHTML = '<div class="skeleton">Loading…</div>';
    document.getElementById('ownerRows').innerHTML = '<tr><td colspan="4" class="skeleton">Loading…</td></tr>';
    document.getElementById('selfGenRows').innerHTML = '<tr><td colspan="4" class="skeleton">Loading…</td></tr>';

    const [salesRes, ranRes] = await Promise.all([
      fetch(salesUrl),
      fetch(ranUrl)
    ]);

    if (!salesRes.ok) {
      document.getElementById('totalSales').textContent = 'ERR';
      return;
    }

    const salesData = await salesRes.json();
    const ranData = ranRes.ok ? await ranRes.json() : null;

    document.getElementById('totalSales').textContent = salesData.result;
    document.getElementById('salesMeta').textContent = '';

    const sbp = (salesData.breakdowns || {}).sales_by_pipeline || {};
    renderVertical(document.getElementById('salesByPipelineV'), sbp);

    // Owner table uses optional Lead Gen Source filter
    const [ownerSalesRes, ownerRanRes] = await Promise.all([
      fetch(`/api/metrics/sales?format=json&year=${encodeURIComponent(y)}&month=${encodeURIComponent(m)}${rp}${ownerLeadParam}`),
      fetch(`/api/metrics/opportunities_ran?format=json&year=${encodeURIComponent(y)}&month=${encodeURIComponent(m)}${rp}${ownerLeadParam}`)
    ]);

    const ownerSalesData = ownerSalesRes.ok ? await ownerSalesRes.json() : { breakdowns: {} };
    const ownerRanData = ownerRanRes.ok ? await ownerRanRes.json() : { breakdowns: {} };

    const salesByOwner = (ownerSalesData.breakdowns || {}).sales_by_owner || {};
    const ranByOwner = (ownerRanData && ownerRanData.breakdowns ? (ownerRanData.breakdowns.ran_by_owner || {}) : {}) || {};

    // union of owners
    const owners = new Set([...Object.keys(salesByOwner||{}), ...Object.keys(ranByOwner||{})]);

    // Aggregate by canonical owner label (merged reps)
    const agg = {};
    for (const owner of owners) {
      const key = canonicalOwner(owner);
      const s = Number(salesByOwner[owner] || 0);
      const r = Number(ranByOwner[owner] || 0);
      if (!agg[key]) agg[key] = { owner: key, ran: 0, sales: 0 };
      agg[key].sales += s;
      agg[key].ran += r;
    }

    const rows = Object.values(agg).map(x => ({ ...x, opp2: pct(x.sales, x.ran) }));

    rows.sort((a,b)=> (b.sales - a.sales) || (b.ran - a.ran) || a.owner.localeCompare(b.owner));

    const totSales = rows.reduce((acc,x)=>acc+x.sales,0);
    const totRan = rows.reduce((acc,x)=>acc+x.ran,0);
    const totOpp2 = pct(totSales, totRan);

    function fmtPct(v) {
      if (v === null || typeof v === 'undefined') return '—';
      return `${v.toFixed(1)}%`;
    }

    let html = '';
    for (const r of rows) {
      html += `
        <tr>
          <td>${r.owner || '—'}</td>
          <td class="num">${r.ran}</td>
          <td class="num">${r.sales}</td>
          <td class="num">${fmtPct(r.opp2)}</td>
        </tr>`;
    }
    html += `
      <tr class="total">
        <td>Total</td>
        <td class="num">${totRan}</td>
        <td class="num">${totSales}</td>
        <td class="num">${fmtPct(totOpp2)}</td>
      </tr>`;

    document.getElementById('ownerRows').innerHTML = html;

    // Self Gen Opps by Setter Last Name
    const [sgCreatedRes, sgDemoRes] = await Promise.all([
      fetch(`/api/metrics/opportunities_created?format=json&year=${encodeURIComponent(y)}&month=${encodeURIComponent(m)}${rp}&pipeline_scope=all&lead_source=${encodeURIComponent('Self Gen')}`),
      fetch(`/api/metrics/demo_rate?format=json&year=${encodeURIComponent(y)}&month=${encodeURIComponent(m)}${rp}&lead_source=${encodeURIComponent('Self Gen')}`)
    ]);

    const sgCreated = sgCreatedRes.ok ? await sgCreatedRes.json() : null;
    const sgDemo = sgDemoRes.ok ? await sgDemoRes.json() : null;

    const createdBySetter = (sgCreated && sgCreated.breakdowns && sgCreated.breakdowns.created_by_setter_last_name) ? sgCreated.breakdowns.created_by_setter_last_name : {};
    const ranBySetter = (sgDemo && sgDemo.breakdowns && sgDemo.breakdowns.ran_by_setter_last_name) ? sgDemo.breakdowns.ran_by_setter_last_name : {};
    const sitBySetter = (sgDemo && sgDemo.breakdowns && sgDemo.breakdowns.sit_by_setter_last_name) ? sgDemo.breakdowns.sit_by_setter_last_name : {};

    const setters = new Set([...Object.keys(createdBySetter||{}), ...Object.keys(ranBySetter||{}), ...Object.keys(sitBySetter||{})]);
    const sgRows = [...setters].map((setter) => {
      const created = Number(createdBySetter[setter] || 0);
      const ran = Number(ranBySetter[setter] || 0);
      const sit = Number(sitBySetter[setter] || 0);
      const demoPct = ran > 0 ? (sit / ran) * 100 : null;
      return { setter, created, ran, demoPct };
    }).sort((a,b) => (b.created - a.created) || (b.ran - a.ran) || a.setter.localeCompare(b.setter));

    let sgHtml = '';
    for (const r of sgRows) {
      sgHtml += `
        <tr>
          <td>${r.setter || '—'}</td>
          <td class="num">${r.created}</td>
          <td class="num">${r.ran}</td>
          <td class="num">${r.demoPct === null ? '—' : `${r.demoPct.toFixed(1)}%`}</td>
        </tr>`;
    }
    if (!sgHtml) sgHtml = '<tr><td colspan="4" class="skeleton">No Self Gen data</td></tr>';
    document.getElementById('selfGenRows').innerHTML = sgHtml;
  }

  const years = [];
  for (let y = defaultYear - 2; y <= defaultYear + 1; y++) years.push({value: y, label: y});
  const months = Array.from({length:12}, (_,i)=>({value:i+1, label: new Date(2000,i,1).toLocaleString('en-US',{month:'long'})}));

  setOptions(yearSel, years, defaultYear);
  setOptions(monthSel, months, defaultMonth);

  document.getElementById('apply').addEventListener('click', () => {
    const s = (document.getElementById('startDate').value || '').trim();
    const e = (document.getElementById('endDate').value || '').trim();
    const u = new URL(window.location.href);
    if (s && e) {
      u.searchParams.set('start', s);
      u.searchParams.set('end', e);
    } else {
      u.searchParams.delete('start');
      u.searchParams.delete('end');
    }
    window.location.href = u.toString();
  });

  document.getElementById('clearRange').addEventListener('click', () => {
    const u = new URL(window.location.href);
    u.searchParams.delete('start');
    u.searchParams.delete('end');
    window.location.href = u.toString();
  });

  const ownerLeadSel = document.getElementById('ownerLeadSource');
  if (ownerLeadSel) ownerLeadSel.addEventListener('change', () => load());

  load();
</script>
</body>
</html>"""

    return html.replace("__YEAR__", str(year)).replace("__MONTH__", str(month))


class handler(BaseHTTPRequestHandler):
    def do_GET(self):
        try:
            qs = parse_qs(urlparse(self.path).query)
            now = datetime.utcnow()
            year = int(qs.get("year", [str(now.year)])[0])
            month = int(qs.get("month", [str(now.month)])[0])

            body = render_html(year, month).encode("utf-8")
            self.send_response(200)
            self.send_header("Content-Type", "text/html; charset=utf-8")
            self.send_header("Cache-Control", "no-store")
            self.end_headers()
            self.wfile.write(body)
        except Exception as e:
            body = ("ERROR: " + str(e)).encode("utf-8")
            self.send_response(500)
            self.send_header("Content-Type", "text/plain; charset=utf-8")
            self.send_header("Cache-Control", "no-store")
            self.end_headers()
            self.wfile.write(body)
